/**
 * @file Объявления встроенных модулей для ресурсов, которые TypeScript
 * не может разрешить самостоятельно.
 *
 * Библиотека Swiper поставляет стили в виде CSS-файлов без объявлений типов,
 * что вызывает ошибку TS2307 («Cannot find module») при их импорте.
 * Эти заглушки сообщают системе проверки типов, что любой импорт вида
 * `swiper/css` или `swiper/css/*` является допустимым модулем.
 */
declare module "swiper/css";
declare module "swiper/css/*";
